PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(SUM(?games) AS ?total) WHERE {
  {
    ?series wdt:P31 wd:Q104182 ; wdt:P1545 wd:Q6307 ; wdt:P1544 wd:Q7800 ; wdt:P580 ?startDate ; wdt:P1585 ?games .
    FILTER(YEAR(?startDate) IN(1977 , 1978 , 2008 , 2009))
  } UNION {
    ?series wdt:P31 wd:Q104182 ; wdt:P1545 wd:Q7800 ; wdt:P1544 wd:Q6307 ; wdt:P580 ?startDate ; wdt:P1585 ?games .
    FILTER(YEAR(?startDate) IN(1977 , 1978 , 2008 , 2009))
  }
}

